using System.ComponentModel;
using System.Drawing.Design;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public partial class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default RenderMode changed from ManagerRenderMode to Professional.
        // Explicitly set to preserve .NET 8 behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        Controls.Add(_statusStrip);
    }

    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    [Editor(typeof(MyDropDownEditor), typeof(UITypeEditor))]
    public object SelectedItem { get; set; }

    // .NET 9: Prefer LibraryImport source generator over DllImport for P/Invoke
    [LibraryImport("user32.dll")]
    internal static partial int GetSystemMetrics(int nIndex);
}

class MyDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
    {
        return UITypeEditorEditStyle.DropDown;
    }

    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService)) as IWindowsFormsEditorService;
        if (editorService != null)
        {
            var control = CreateDropDownControl(value);
            // .NET 9: DropDownControl(null) now throws ArgumentNullException
            if (control != null)
            {
                editorService.DropDownControl(control);
            }
        }
        return value;
    }

    private Control CreateDropDownControl(object value)
    {
        return value != null ? new ListBox() : null;
    }
}

